previewCss:
.darma-loader-darma-custom-515 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: var(--loader-secondary-color, #c084fc);
  --loader-bg: var(--loader-bg, #ffffff);
   height: 40px;
   aspect-ratio: 1.5;
   --c:no-repeat linear-gradient(currentColor 0 0);
   background:var(--c), var(--c);
   background-size: 66% 50%;
   animation: darma-loader-darma-custom-515-l1 1.5s infinite linear;
}
@keyframes darma-loader-darma-custom-515-l1  {
  0% {background-position:0 0,0 100%}
25% {background-position:100% 0,0 100%}
47%, 53% {background-position:100% 0,100% 100%}
75% {background-position:0 0,100% 100%}
100%{background-position:0 0,0 100%}
}

